const input = $json;
const previousFeedback = input.previous_feedback || '';
const isRetry = previousFeedback.trim().length > 0;
const planDocument = input.plan_document || '';

let taskDescription = input.task?.description || input.description || '';
if (!taskDescription && input.task?.raw_output) {
  const raw = input.task.raw_output;
  const cleaned = raw.replace(/<\/?task>/g, '').replace(/\n+(?:Reasoning|Note):[\s\S]*/i, '').trim();
  try {
    const parsed = JSON.parse(cleaned);
    const list = Array.isArray(parsed) ? parsed : (parsed.tasks || []);
    taskDescription = list.map(t => `${t.task_id}: ${t.description}`).join('\n\n');
  } catch(e) { taskDescription = raw; }
}

const taskFiles = (input.task || {}).files || [];
const filesConstraint = taskFiles.length > 0
  ? '\n\nFILES TO MODIFY (ONLY output these files):\n' + taskFiles.join('\n')
  : '';

const existingFiles = input.existing_files || [];
const existingFilesSection = existingFiles.length > 0
  ? '\n\nEXISTING PROJECT FILES (modify or extend these \u2014 do NOT rewrite files that do not need changes):\n' +
    existingFiles.map(f => `### ${f.path}\n\`\`\`\n${f.content}\n\`\`\``).join('\n\n')
  : '';

let userContent;
if (isRetry) {
  userContent = `Task:\n${taskDescription}${filesConstraint}${existingFilesSection}\n\nIssues found in your previous code. Fix ALL of them:\n\n${previousFeedback}\n\nOutput only the files that need to change, using the ### path/to/file.ext \`\`\`lang ... \`\`\` format.`;
} else {
  userContent = `Task:\n${taskDescription}${filesConstraint}${existingFilesSection}`;
}

let systemMessage = `You are a Senior Full-Stack Developer. Output ONLY the files that need to be created or changed. Do not output files that are already correct.\n\nTech Stack: TypeScript, Node.js/Express, React/Vite, PostgreSQL/Prisma\n\nFor EACH file you need to create or modify, output EXACTLY this format:\n### path/to/file.ts\n\`\`\`ts\n[complete file content]\n\`\`\`\n\nRULES:\n- Only output files that this task requires you to create or change\n- Output complete file content (not diffs)\n- No explanations, no numbered lists, no prose \u2014 ONLY the file blocks\n- NEVER output files that are not listed in the FILES TO MODIFY section`;

if (planDocument) {
  systemMessage += `\n\nARCHITECTURE REFERENCE (follow this plan):\n${planDocument}`;
}

return [{ json: {
  model: $env.CODER_MODEL || 'qwen/qwen2.5-coder-32b-instruct',
  messages: [
    { role: 'system', content: systemMessage },
    { role: 'user', content: userContent }
  ],
  temperature: 0.7,
  max_tokens: 16000,
  stop: ['<|fim_suffix|>', '<|fim_prefix|>', '<|fim_middle|>', '<|endoftext|>']
} }];

const raw = $json.choices[0].message.content || $json.choices[0].message.reasoning_content || '';
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) {
  content = content.split('</think>').pop().trim();
}
const files = [];
const seen = new Set();
const re = /###\s+((?:[\w.-]+\/)*(?:\.\w[\w.-]*|[\w.-]+\.(?:ts|tsx|js|jsx|json|md|yml|yaml|env|prisma|css|html|sh|txt|lock|toml|cfg|ini)|Dockerfile|Makefile|LICENSE|CHANGELOG))\s*\n```[\w]*\n([\s\S]*?)```/g;
let m;
while ((m = re.exec(content)) !== null) {
  const path = m[1].trim();
  const fileContent = m[2];
  if (path && !seen.has(path)) {
    seen.add(path);
    files.push({ path, content: fileContent });
  }
}
const trigger = $('Execute Workflow Trigger').first().json;
return [{ json: { files, task: trigger.task, project_goal: trigger.project_goal } }];
